"use strict";document.addEventListener("DOMContentLoaded",function(){const e=document.getElementById("counterValue"),t=document.getElementById("decrementButton"),n=document.getElementById("incrementButton");let o=0;t.addEventListener("click",function(){o-=1,e.textContent=o,console.log("The counter was decreased to: "+o)}),n.addEventListener("click",function(){o+=1,e.textContent=o,console.log("The counter was increased to: "+o)})});